<?php
$pageTitle='Bank Reconciliation';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('bank_reconciliation');
$pdo=getDB();
$bankAccounts=$pdo->query('SELECT * FROM '.table('bank_accounts').' WHERE active=1 ORDER BY account_name')->fetchAll();
$bankId=(int)($_GET['bank_account_id']??($bankAccounts[0]['id']??0));
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'');
    if($action==='add_statement'){
      $bankId=(int)$_POST['bank_account_id'];
      $pdo->prepare('INSERT INTO '.table('bank_statement_lines').' (bank_account_id,statement_date,description,reference,debit,credit,status) VALUES (?,?,?,?,?,?,"unmatched")')->execute([$bankId,trim((string)$_POST['statement_date']),trim((string)$_POST['description']),trim((string)$_POST['reference']),max(0,(float)$_POST['debit']),max(0,(float)$_POST['credit'])]);
      flash('success','Statement line added.');
    }elseif($action==='match_line'){
      $pdo->prepare('UPDATE '.table('bank_statement_lines').' SET matched_journal_line_id=?,status="matched",reconciled_at=NOW() WHERE id=?')->execute([(int)$_POST['journal_line_id'],(int)$_POST['statement_id']]);flash('success','Statement line matched.');
    }elseif($action==='create_recon'){
      $bankId=(int)$_POST['bank_account_id'];createBankReconciliation($pdo,$bankId,trim((string)$_POST['date_from']),trim((string)$_POST['date_to']),(float)$_POST['statement_ending_balance'],trim((string)$_POST['notes']));flash('success','Bank reconciliation created.');
    }elseif($action==='mark_reconciled'){
      $id=(int)$_POST['id'];$user=currentUser();$pdo->prepare('UPDATE '.table('bank_reconciliations').' SET status="reconciled",reconciled_by=?,reconciled_at=NOW() WHERE id=? AND ABS(variance)<0.01')->execute([(int)($user['id']??0)?:null,$id]);flash('success','Reconciliation marked as reconciled if variance is zero.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'bank-reconciliation']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/bank-reconciliation.php?bank_account_id='.$bankId);
}
$lines=[];$recons=[];$journalLines=[];
if($bankId){
  $stmt=$pdo->prepare('SELECT * FROM '.table('bank_statement_lines').' WHERE bank_account_id=? ORDER BY statement_date DESC,id DESC LIMIT 150');$stmt->execute([$bankId]);$lines=$stmt->fetchAll();
  $stmt=$pdo->prepare('SELECT r.*,b.account_name FROM '.table('bank_reconciliations').' r LEFT JOIN '.table('bank_accounts').' b ON b.id=r.bank_account_id WHERE r.bank_account_id=? ORDER BY r.created_at DESC LIMIT 50');$stmt->execute([$bankId]);$recons=$stmt->fetchAll();
  $bank=$pdo->prepare('SELECT cash_account_id FROM '.table('bank_accounts').' WHERE id=? LIMIT 1');$bank->execute([$bankId]);$cashId=(int)$bank->fetchColumn();
  if($cashId>0){$jl=$pdo->prepare('SELECT jl.id,je.journal_number,je.entry_date,jl.description,jl.debit,jl.credit FROM '.table('journal_lines').' jl INNER JOIN '.table('journal_entries').' je ON je.id=jl.journal_entry_id WHERE jl.account_id=? AND je.status="posted" ORDER BY je.entry_date DESC LIMIT 100');$jl->execute([$cashId]);$journalLines=$jl->fetchAll();}
}
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Cash Control</div><h2 class="h4 mb-1">Bank Reconciliation</h2><p class="text-secondary mb-0">Record statement lines, match bank movements, calculate book variance, and finalize reconciliations.</p></div><a class="btn btn-outline-primary" href="<?php echo esc(ADMIN_URL); ?>/erp/bank-accounts.php"><?php echo t('Bank Accounts', 'الحسابات البنكية'); ?></a></div>
<div class="row g-4"><div class="col-xl-4"><form class="card-admin p-4 mb-4"><label class="form-label">Bank Account</label><select class="form-select" name="bank_account_id" onchange="this.form.submit()"><?php foreach($bankAccounts as $b): ?><option value="<?php echo (int)$b['id']; ?>" <?php echo $bankId===(int)$b['id']?'selected':''; ?>><?php echo esc($b['account_name'].' · '.$b['bank_name']); ?></option><?php endforeach; ?></select></form><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="create_recon"><input type="hidden" name="bank_account_id" value="<?php echo (int)$bankId; ?>"><h2 class="h5 mb-3">Create Reconciliation</h2><div class="row g-2"><div class="col-6"><label class="form-label">From</label><input class="form-control" type="date" name="date_from" value="<?php echo esc(date('Y-m-01')); ?>"></div><div class="col-6"><label class="form-label">To</label><input class="form-control" type="date" name="date_to" value="<?php echo esc(date('Y-m-t')); ?>"></div></div><label class="form-label mt-2">Statement Ending Balance</label><input class="form-control mb-2" type="number" step="0.01" name="statement_ending_balance" value="0"><label class="form-label">Notes</label><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-brand w-100">Create Reconciliation</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="add_statement"><input type="hidden" name="bank_account_id" value="<?php echo (int)$bankId; ?>"><h2 class="h5 mb-3">Add Statement Line</h2><input class="form-control mb-2" type="date" name="statement_date" value="<?php echo esc(date('Y-m-d')); ?>"><input class="form-control mb-2" name="description" placeholder="Description"><input class="form-control mb-2" name="reference" placeholder="Reference"><div class="row g-2"><div class="col-6"><input class="form-control" type="number" step="0.01" name="debit" placeholder="Debit"></div><div class="col-6"><input class="form-control" type="number" step="0.01" name="credit" placeholder="Credit"></div></div><button class="btn btn-outline-primary w-100 mt-3">Add Line</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Reconciliation Runs</h2><table class="table align-middle"><thead><tr><th>Recon</th><th>Range</th><th>Statement</th><th>Book</th><th>Variance</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($recons as $r): ?><tr><td><strong><?php echo esc($r['reconciliation_number']); ?></strong></td><td><?php echo esc($r['date_from'].' → '.$r['date_to']); ?></td><td><?php echo money($r['statement_ending_balance']); ?></td><td><?php echo money($r['book_ending_balance']); ?></td><td class="<?php echo abs((float)$r['variance'])>0.01?'money-negative':'money-positive'; ?>"><?php echo money($r['variance']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($r['status'])); ?>"><?php echo esc($r['status']); ?></span></td><td><?php if($r['status']!=='reconciled'): ?><form method="post"><input type="hidden" name="action" value="mark_reconciled"><input type="hidden" name="id" value="<?php echo (int)$r['id']; ?>"><button class="btn btn-sm btn-outline-success">Finalize</button></form><?php endif; ?></td></tr><?php endforeach; ?><?php if(!$recons): ?><tr><td colspan="7" class="text-secondary">No reconciliations yet.</td></tr><?php endif; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Statement Lines</h2><table class="table align-middle"><thead><tr><th>Date</th><th>Description</th><th>Debit</th><th>Credit</th><th>Status</th><th>Match</th></tr></thead><tbody><?php foreach($lines as $line): ?><tr><td><?php echo esc($line['statement_date']); ?></td><td><strong><?php echo esc($line['description']); ?></strong><div class="small text-secondary"><?php echo esc($line['reference']); ?></div></td><td><?php echo money($line['debit']); ?></td><td><?php echo money($line['credit']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($line['status'])); ?>"><?php echo esc($line['status']); ?></span></td><td><?php if($line['status']!=='matched'): ?><form method="post" class="d-flex gap-1"><input type="hidden" name="action" value="match_line"><input type="hidden" name="statement_id" value="<?php echo (int)$line['id']; ?>"><select class="form-select form-select-sm" name="journal_line_id"><?php foreach($journalLines as $jl): ?><option value="<?php echo (int)$jl['id']; ?>"><?php echo esc($jl['journal_number'].' · '.$jl['entry_date'].' · '.money((float)$jl['debit']-(float)$jl['credit'])); ?></option><?php endforeach; ?></select><button class="btn btn-sm btn-outline-primary">Match</button></form><?php endif; ?></td></tr><?php endforeach; ?><?php if(!$lines): ?><tr><td colspan="6" class="text-secondary">No statement lines.</td></tr><?php endif; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>